SELECT o.*, c.name as customer_name, c.phone as customer_phone, r.room_no, rt.name as room_type_name, u.real_name as user_name
FROM t_order o
LEFT JOIN t_customer c ON o.customer_id = c.id
LEFT JOIN t_room r ON o.room_id = r.id
LEFT JOIN t_room_type rt ON r.type_id = rt.id
LEFT JOIN sys_user u ON o.user_id = u.id


        AND o.status = #{status}


        AND (c.name LIKE CONCAT('%', #{keyword}, '%') OR r.room_no LIKE CONCAT('%', #{keyword}, '%')
             OR o.order_no LIKE CONCAT('%', #{keyword}, '%') OR c.phone LIKE CONCAT('%', #{keyword}, '%'))


        AND o.check_in_time >= #{startTime}


        AND o.check_in_time <= #{endTime}


ORDER BY o.create_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM t_order o
LEFT JOIN t_customer c ON o.customer_id = c.id
LEFT JOIN t_room r ON o.room_id = r.id


        AND o.status = #{status}


        AND (c.name LIKE CONCAT('%', #{keyword}, '%') OR r.room_no LIKE CONCAT('%', #{keyword}, '%')
             OR o.order_no LIKE CONCAT('%', #{keyword}, '%') OR c.phone LIKE CONCAT('%', #{keyword}, '%'))


        AND o.check_in_time >= #{startTime}


